      "content": "package com.entropy.factory;

import com.entropy.factory.model.Component;
import com.entropy.factory.model.Station;
import com.entropy.factory.model.Product;
import com.entropy.factory.model.Routing;
import java.util.List;
import java.util.Map;
import java.util.HashMap;

public class FactorySystem {
    // Entry point for the factory system
    // This class will orchestrate the core concepts

    private Map<String, Station> stations;
    private Map<String, Routing> routings;

    public FactorySystem() {
        this.stations = new HashMap<>();
        this.routings = new HashMap<>();
        initializeStations();
        initializeRoutings();
    }

    private void initializeStations() {
        Station assemblyStation = new Station("station-001", "Assembly Station", List.of("motor", "wheels", "frame"));
        Station inspectionStation = new Station("station-002", "Inspection Station", List.of("motor", "wheels", "frame", "battery"));
        Station packagingStation = new Station("station-003", "Packaging Station", List.of("finished_product"));

        stations.put(assemblyStation.getId(), assemblyStation);
        stations.put(inspectionStation.getId(), inspectionStation);
        stations.put(packagingStation.getId(), packagingStation);
    }

    private void initializeRoutings() {
        Routing productA = new Routing("product-A", List.of("station-001", "station-002", "station-003"));
        Routing productB = new Routing("product-B", List.of("station-001", "station-002", "station-003"));

        routings.put(productA.getProductId(), productA);
        routings.put(productB.getProductId(), productB);
    }

    public Station getStation(String stationId) {
        return stations.get(stationId);
    }

    public Routing getRouting(String productId) {
        return routings.get(productId);
    }

    public List<String> getStationSequence(String productId) {
        Routing routing = routings.get(productId);
        return routing != null ? routing.getStationSequence() : null;
    }
}"
    }
  ],
  "notes": "Added multiple stations and routing flow to FactorySystem to enable product movement between stations."
}
